  function renderRisk() {
    const { code, name } = selectedGong;
    const nameEl = document.getElementById('risk-gong-name');
    if (nameEl) nameEl.innerHTML = code + ' ' + name + ' 기준<br>해당하는 요인을 모두 선택하세요';

    const listEl = document.getElementById('risk-list');
    if (!listEl) return;

    const data = riskData[code];
    if (!data) {
      listEl.innerHTML = '<div style="padding:16px;color:#999;font-size:14px;">해당 공종의 위험성평가 데이터가 없습니다.</div>';
      return;
    }

    riskOrder = [];
    document.getElementById('daily-banner').style.display = 'none';

    let inner = '';
    data.forEach(item => {
      inner += `<div class="risk-item" onclick="toggleRisk(this)" data-countermeasure="${item.cm}">
        <div class="risk-check"></div>
        <div style="flex:1;">
          <div class="risk-text">${item.text}</div>
          <div class="risk-counter" style="font-size:12px;color:var(--primary);margin-top:5px;padding-top:5px;border-top:1px solid var(--border);">→ ${item.cm}</div>
        </div>
      </div>`;
    });
    listEl.innerHTML = inner;
  }

